styles:
:root{--bg:#111827;--card:#1f2937;--line:#374151;--text:#e5e7eb;--muted:#9ca3af;--ok:#34d399;--bad:#fb7185;--accent:#60a5fa}
*{box-sizing:border-box}html,body{margin:0;background:var(--bg);color:var(--text);font:14px/1.55 system-ui,"Microsoft YaHei",sans-serif}
main.suite-shell{max-width:1500px;margin:auto;padding:24px}h1{font-size:24px;margin:0 0 8px}.lede{color:var(--muted);margin:0 0 16px}
.summary{display:grid;grid-template-columns:repeat(5,minmax(110px,1fr));gap:8px;margin:14px 0}.metric{background:var(--card);border:1px solid var(--line);border-radius:10px;padding:10px}.metric b{display:block;font-size:20px}
table.suite-table{width:100%;border-collapse:collapse;background:var(--card);border:1px solid var(--line)}.suite-table>thead>tr>th,.suite-table>tbody>tr>td{border-bottom:1px solid var(--line);padding:9px;text-align:left;vertical-align:top}.suite-table>thead>tr>th{position:sticky;top:0;background:#172033;z-index:2}.suite-table>tbody>tr>td:nth-child(1){white-space:nowrap;font-weight:700}.suite-table>tbody>tr>td:nth-child(2){min-width:145px}.suite-table>tbody>tr>td:nth-child(4){min-width:260px}.suite-table>tbody>tr>td:nth-child(5){min-width:340px}code{display:block;white-space:pre-wrap;word-break:break-word;color:#bfdbfe}pre{margin:0;white-space:pre-wrap;word-break:break-word}.artifact-stage{background:#f8fafc;color:#0f172a}.library-artifact{min-height:62px;padding:9px;border:1px solid #cbd5e1;border-radius:9px;background:white;overflow:auto}.artifact-label{display:block;color:#334155;margin-bottom:6px}.artifact-content canvas,.artifact-content svg,.artifact-content img{max-width:100%;height:auto}.artifact-content table{color:#0f172a;background:white;border-color:#cbd5e1}.artifact-content td,.artifact-content th{border-color:#cbd5e1;padding:3px;position:static;background:white}.checks{list-style:none;margin:0;padding:0}.checks li{margin:0 0 7px;padding:7px;border-radius:7px;background:#172033}.checks b{display:block}.check-pass b{color:var(--ok)}.check-fail b{color:var(--bad)}details{margin-top:7px}.badge{display:inline-block;padding:2px 7px;border-radius:999px;background:#374151}.foot{color:var(--muted);margin-top:12px}@media(max-width:900px){.summary{grid-template-columns:repeat(2,1fr)}.suite-table>thead>tr>th:nth-child(2),.suite-table>tbody>tr>td:nth-child(2){display:none}}
